Patch Set 10:

(5 comments)

Patch looks generally good.

At least sanity test_129 still needs to be fixed, since it is failing because it can't find the right block device to use:

 CMD: trevis-8vm4 dv=\$(/usr/sbin/lctl get_param -n *.lustre-MDT0000.mntdev);
			 if foo=\$(lvdisplay -c \$dv 2>/dev/null); then
				echo dm-\${foo##*:};
			 else
				name=\$(basename \$dv);
				if [[ \$name = *flakey* ]]; then
					name=\$(lsblk -o NAME,KNAME |
						 awk /\$name/'{print \$4}');
				fi;
				echo \$name;
			 fi;
 CMD: trevis-8vm4 test -e /proc/fs/ldiskfs//max_dir_size
 CMD: trevis-8vm4 echo 20480 >/sys/fs/ldiskfs//max_dir_size
